import{c as a,Q as t,j as r,m as s}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Context Rot: How Increasing Input Tokens Impacts LLM Performance","description":"","frontmatter":{"title":"Context Rot: How Increasing Input Tokens Impacts LLM Performance","author":"Chroma Research","date":"2026-04-30T00:00:00.000Z","source":"https://www.trychroma.com/research/context-rot","tags":["agent-harness","research"]},"headers":[],"relativePath":"research/agent-harness/references/2026-04-30-context-rot-chroma.md","filePath":"research/agent-harness/references/2026-04-30-context-rot-chroma.md","lastUpdated":1779894392000}'),n={name:"research/agent-harness/references/2026-04-30-context-rot-chroma.md"};function o(i,e,c,l,d,h){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="context-rot-how-increasing-input-tokens-impacts-llm-performance" tabindex="-1">Context Rot: How Increasing Input Tokens Impacts LLM Performance <a class="header-anchor" href="#context-rot-how-increasing-input-tokens-impacts-llm-performance" aria-label="Permalink to &quot;Context Rot: How Increasing Input Tokens Impacts LLM Performance&quot;">​</a></h1><h2 id="core-discovery" tabindex="-1">Core Discovery <a class="header-anchor" href="#core-discovery" aria-label="Permalink to &quot;Core Discovery&quot;">​</a></h2><p>The report reveals that <strong>LLMs do not process context uniformly</strong>. Despite claims of handling long contexts reliably, models exhibit &quot;increasingly unreliable&quot; performance as input length grows, even on simple tasks.</p><h2 id="primary-quantified-metrics" tabindex="-1">Primary Quantified Metrics <a class="header-anchor" href="#primary-quantified-metrics" aria-label="Permalink to &quot;Primary Quantified Metrics&quot;">​</a></h2><p><strong>Performance Degradation Patterns:</strong></p><ul><li>Models show non-uniform performance decay across different input lengths</li><li>Lower needle-question similarity accelerates performance decline</li><li>Even single distractors measurably reduce accuracy compared to baseline</li></ul><p><strong>Model-Specific Behaviors:</strong></p><ul><li>Claude models demonstrate conservative responses under ambiguity, often abstaining when uncertain</li><li>GPT models show highest hallucination rates when distractors present</li><li>Gemini and Qwen models generate spurious content at extended lengths (500+ words)</li></ul><h2 id="niah-benchmark-extensions" tabindex="-1">NIAH Benchmark Extensions <a class="header-anchor" href="#niah-benchmark-extensions" aria-label="Permalink to &quot;NIAH Benchmark Extensions&quot;">​</a></h2><p>The researchers tested beyond traditional lexical-matching NIAH by examining:</p><h3 id="_1-semantic-similarity" tabindex="-1">1. Semantic Similarity <a class="header-anchor" href="#_1-semantic-similarity" aria-label="Permalink to &quot;1. Semantic Similarity&quot;">​</a></h3><p>Needle-question pairs ranging from 0.445-0.829 cosine similarity showed faster degradation at lower similarity scores</p><h3 id="_2-distractors-impact" tabindex="-1">2. Distractors Impact <a class="header-anchor" href="#_2-distractors-impact" aria-label="Permalink to &quot;2. Distractors Impact&quot;">​</a></h3><p>Adding four topically-related distractors caused compounded performance drops, with individual distractors showing non-uniform impact</p><h3 id="_3-structural-effects" tabindex="-1">3. Structural Effects <a class="header-anchor" href="#_3-structural-effects" aria-label="Permalink to &quot;3. Structural Effects&quot;">​</a></h3><p>Surprisingly, shuffled haystacks consistently outperformed logically coherent ones across all 18 models tested</p><h3 id="_4-longmemeval-results" tabindex="-1">4. LongMemEval Results <a class="header-anchor" href="#_4-longmemeval-results" aria-label="Permalink to &quot;4. LongMemEval Results&quot;">​</a></h3><p>On conversational QA with 113k tokens, focused prompts (~300 tokens) substantially outperformed full prompts, with Claude Opus 4 showing the largest gap</p><h2 id="repeated-words-task" tabindex="-1">Repeated Words Task <a class="header-anchor" href="#repeated-words-task" aria-label="Permalink to &quot;Repeated Words Task&quot;">​</a></h2><p>Models failed to accurately replicate simple repeated-word sequences beyond 2,500 tokens, with position-accuracy declining as length increased and random word generation appearing at extended lengths.</p>',20)])])}const u=a(n,[["render",o]]);export{p as __pageData,u as default};
